class Solution {
    public double new21Game(int n, int k, int maxPts) {
        if (k == 0) return 1.0;
        if (k > n) return 0.0;

        int size = Math.max(n, k - 1 + maxPts);
        double[] dp = new double[size + 1];

        for (int j = 0; j <= size; j++) {
            if (j >= k) {
                dp[j] = (j <= n) ? 1.0 : 0.0;
            } else {
                dp[j] = 0.0;
            }
        }

        for (int i = k - 1; i >= 0; i--) {
            double sum = 0.0;
            for (int x = 1; x <= maxPts; x++) {
                int j = i + x;
                if (j >= k) {
                    if (j <= n) {
                        sum += 1.0;
                    }
                } else {
                    sum += dp[j];
                }
            }
            dp[i] = sum / maxPts;
        }

        return dp[0];
    }
}

